338→func (a *Agent) captureTranscriptForStop(cwd string, sessionID string, conversationID string) string {
339→	// Try IDE workspace sessions first — the stop hook is fired by the IDE,
340→	// so IDE data is the most accurate source. CLI DB is a fallback for
341→	// kiro-cli (non-IDE) sessions where no IDE workspace data exists.
342→	if sessionRef, err := a.ensureIDETranscript(cwd, sessionID); err == nil && sessionRef != "" {
343→		return sessionRef
344→	}
345→	if sessionRef, err := a.ensureCachedTranscript(cwd, sessionID, conversationID); err == nil && sessionRef != "" {
346→		return sessionRef
347→	}
348→	return a.createPlaceholderTranscript(cwd, sessionID)
349→}
