690→func extractFilePath(args json.RawMessage) string {
691→	if len(args) == 0 {
692→		return ""
693→	}
694→
695→	var fields map[string]json.RawMessage
696→	if err := json.Unmarshal(args, &fields); err != nil {
697→		return ""
698→	}
699→
700→	for _, key := range []string{"path", "file_path", "filename", "file"} {
701→		raw, ok := fields[key]
702→		if !ok {
703→			continue
704→		}
705→		var path string
706→		if err := json.Unmarshal(raw, &path); err == nil && path != "" {
707→			return path
708→		}
709→	}
710→	return ""
711→}
