599→// buildTranscript creates a kiro CLI transcript with the given number of prompt entries.
600→func buildTranscript(convID string, numPrompts int) []byte {
601→	var entries []kiroHistoryEntry
602→	for i := range numPrompts {
603→		promptJSON, _ := json.Marshal(kiroPromptContent{
604→			Prompt: struct {
605→				Prompt string `json:"prompt"`
606→			}{Prompt: fmt.Sprintf("prompt %d", i)},
607→		})
608→		entries = append(entries, kiroHistoryEntry{
609→			User: kiroUserMessage{Content: promptJSON},
610→		})
611→	}
612→	transcript := kiroTranscript{ConversationID: convID, History: entries}
613→	data, _ := json.Marshal(transcript)
614→	return data
615→}
