 75→func (a *Agent) querySessionID(cwd string) (string, error) {
 76→	db, err := kiroCLIDataDBPath()
 77→	if err != nil {
 78→		return "", err
 79→	}
 80→	if _, err := os.Stat(db); err != nil {
 81→		return "", fmt.Errorf("kiro database not found at %s: %w", db, err)
 82→	}
 83→
 84→	query := fmt.Sprintf(
 85→		"SELECT json_extract(value, '$.conversation_id') FROM conversations_v2 WHERE key = '%s' ORDER BY updated_at DESC LIMIT 1",
 86→		escapeSQLString(cwd),
 87→	)
 88→
 89→	out, err := runSQLiteCommand("-json", db, query)
 90→	if err != nil {
 91→		return "", fmt.Errorf("sqlite3 query failed: %w", err)
 92→	}
 93→
 94→	result := strings.TrimSpace(string(out))
 95→	if result == "" || result == "[]" {
 96→		return "", nil
 97→	}
 98→
 99→	var rows []map[string]string
100→	if err := json.Unmarshal([]byte(result), &rows); err != nil {
101→		return "", fmt.Errorf("failed to parse sqlite3 output: %w", err)
102→	}
103→	if len(rows) == 0 {
104→		return "", nil
105→	}
106→	for _, value := range rows[0] {
107→		return value, nil
108→	}
109→	return "", nil
110→}
