187→func writeTranscriptOffset(path string, offset transcriptOffset) error {
188→	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
189→		return err
190→	}
191→	data, err := json.Marshal(offset)
192→	if err != nil {
193→		return err
194→	}
195→	return os.WriteFile(path, data, 0o600)
