240→func (a *Agent) ensureIDETranscript(cwd string, sessionID string) (string, error) {
241→	sessionsDir, err := ideWorkspaceSessionsDir(cwd)
242→	if err != nil {
243→		return "", err
244→	}
245→
246→	indexPath := filepath.Join(sessionsDir, "sessions.json")
247→	indexData, err := os.ReadFile(indexPath)
248→	if err != nil {
249→		return "", fmt.Errorf("IDE sessions.json not found: %w", err)
250→	}
251→
252→	var sessions []ideSessionIndexEntry
253→	if err := json.Unmarshal(indexData, &sessions); err != nil {
254→		return "", fmt.Errorf("failed to parse IDE sessions.json: %w", err)
255→	}
256→	if len(sessions) == 0 {
257→		return "", errors.New("no IDE sessions found")
258→	}
259→
260→	sort.Slice(sessions, func(i, j int) bool {
261→		return sessions[i].DateCreated > sessions[j].DateCreated
262→	})
263→
264→	ideSessionID := sessions[0].SessionID
265→	if !filepath.IsLocal(ideSessionID + ".json") {
266→		return "", fmt.Errorf("invalid session ID: %q", ideSessionID)
267→	}
268→
269→	transcriptPath := filepath.Join(sessionsDir, ideSessionID+".json")
270→	transcriptData, err := os.ReadFile(transcriptPath)
271→	if err != nil {
272→		return "", fmt.Errorf("failed to read IDE transcript %s: %w", transcriptPath, err)
273→	}
274→
275→	// Enrich the IDE transcript with actual agent responses and tool calls.
276→	// The IDE session format only stores "On it." as assistant content.
277→	//
278→	// Priority 1: Read Kiro IDE execution logs — these contain the full
279→	// action trace (tool calls, responses, file modifications).
280→	// Priority 2: Merge tool calls from post-tool-use hook JSONL file.
281→	data := transcriptData
282→	enriched := false
283→	if chatSessionID := extractIDESessionID(transcriptData); chatSessionID != "" {
284→		if execLogs, err := findExecutionLogsForSession(chatSessionID); err == nil && len(execLogs) > 0 {
285→			if result := enrichIDETranscriptWithExecutionLogs(transcriptData, execLogs); result != nil {
286→				data = result
287→				enriched = true
288→			}
289→		}
290→	}
291→	if !enriched {
292→		if toolCalls := a.readAndClearToolCalls(); len(toolCalls) > 0 {
293→			if result := enrichIDETranscriptWithToolCalls(transcriptData, toolCalls); result != nil {
294→				data = result
295→			}
296→		}
297→	}
298→
299→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
300→	if err != nil {
301→		return "", err
302→	}
303→	if err := os.WriteFile(cachePath, data, 0o600); err != nil {
304→		return "", fmt.Errorf("failed to write cached IDE transcript: %w", err)
305→	}
306→	return cachePath, nil
307→}
