455→func (a *Agent) ExtractPrompts(path string, offset int) ([]string, error) {
456→	transcript, err := readAndParseTranscript(path)
457→	if errors.Is(err, os.ErrNotExist) {
458→		return nil, nil
459→	}
460→	if err != nil {
461→		return nil, err
462→	}
463→
464→	var prompts []string
465→	for i := offset; i < len(transcript.History); i++ {
466→		if prompt := extractUserPrompt(transcript.History[i].User.Content); prompt != "" {
467→			prompts = append(prompts, prompt)
468→		}
469→	}
470→	return prompts, nil
471→}
