663→func extractFilesFromAssistant(raw json.RawMessage) []string {
664→	if len(raw) == 0 {
665→		return nil
666→	}
667→
668→	var toolUseContent kiroToolUseContent
669→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
670→		return nil
671→	}
672→
673→	var paths []string
674→	for _, call := range toolUseContent.ToolUse.ToolUses {
675→		if !isFileModificationTool(call.Name) {
676→			continue
677→		}
678→		if path := extractFilePath(call.Args); path != "" {
679→			paths = append(paths, path)
