713→func extractLastAssistantResponse(entries []kiroHistoryEntry) string {
714→	for i := len(entries) - 1; i >= 0; i-- {
715→		if len(entries[i].Assistant) == 0 {
716→			continue
717→		}
718→
719→		var responseContent kiroResponseContent
720→		if err := json.Unmarshal(entries[i].Assistant, &responseContent); err == nil && responseContent.Response.Content != "" {
721→			return responseContent.Response.Content
722→		}
723→	}
