754→// findExecutionLogsForSession scans Kiro IDE workspace directories to find
755→// execution log files matching the given chat session ID. Returns a map of
756→// executionId → *kiroExecutionLog.
757→func findExecutionLogsForSession(chatSessionID string) (map[string]*kiroExecutionLog, error) {
758→	baseDir, err := kiroExtensionStorageDir()
759→	if err != nil {
760→		return nil, err
761→	}
762→
763→	entries, err := os.ReadDir(baseDir)
764→	if err != nil {
765→		return nil, err
766→	}
767→
768→	for _, entry := range entries {
769→		if !entry.IsDir() || len(entry.Name()) != 32 {
770→			continue
771→		}
772→		logsDir := filepath.Join(baseDir, entry.Name(), execLogsSubdir)
773→		if _, err := os.Stat(logsDir); err != nil {
774→			continue
775→		}
776→		logs := scanExecutionLogsDir(logsDir, chatSessionID)
777→		if len(logs) > 0 {
778→			return logs, nil
779→		}
780→	}
781→
782→	return map[string]*kiroExecutionLog{}, nil
783→}
784→
785→// scanExecutionLogsDir reads all execution log files in a directory and returns
786→// those matching the given chat session ID.
787→func scanExecutionLogsDir(dir string, chatSessionID string) map[string]*kiroExecutionLog {
788→	files, err := os.ReadDir(dir)
789→	if err != nil {
790→		return nil
791→	}
792→
793→	// Two-pass approach: first identify matching files using a lightweight
794→	// struct (avoids deserializing the large Actions array), then fully
795→	// parse only the matches.
796→	var matchingPaths []string
797→	for _, f := range files {
798→		if f.IsDir() {
799→			continue
800→		}
801→		path := filepath.Join(dir, f.Name())
802→		data, err := os.ReadFile(path)
803→		if err != nil {
804→			continue
805→		}
806→		var header struct {
807→			ChatSessionID string `json:"chatSessionId"`
808→		}
809→		if json.Unmarshal(data, &header) == nil && header.ChatSessionID == chatSessionID {
810→			matchingPaths = append(matchingPaths, path)
811→		}
812→	}
813→
814→	if len(matchingPaths) == 0 {
815→		return nil
816→	}
817→
818→	result := make(map[string]*kiroExecutionLog, len(matchingPaths))
819→	for _, path := range matchingPaths {
820→		data, err := os.ReadFile(path)
821→		if err != nil {
822→			continue
823→		}
824→		var log kiroExecutionLog
825→		if err := json.Unmarshal(data, &log); err != nil {
826→			continue
827→		}
828→		result[log.ExecutionID] = &log
829→	}
830→	return result
831→}
