 46→func (a *Agent) ParseHook(hookName string, input []byte) (*protocol.EventJSON, error) {
 47→	var raw hookInputRaw
 48→	if len(input) > 0 {
 49→		if err := json.Unmarshal(input, &raw); err != nil {
 50→			return nil, err
 51→		}
 52→	}
 53→
 54→	switch hookName {
 55→	case HookNameAgentSpawn:
 56→		sessionID := a.generateAndCacheSessionID()
 57→		return &protocol.EventJSON{
 58→			Type:      1,
 59→			SessionID: sessionID,
 60→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 61→		}, nil
 62→	case HookNameUserPromptSubmit:
 63→		sessionID := a.readCachedSessionID()
 64→		if sessionID == "" {
 65→			sessionID = a.generateAndCacheSessionID()
 66→		}
 67→		prompt := raw.Prompt
 68→		if prompt == "" {
 69→			prompt = os.Getenv("USER_PROMPT")
 70→		}
 71→		return &protocol.EventJSON{
 72→			Type:      2,
 73→			SessionID: sessionID,
 74→			Prompt:    prompt,
 75→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 76→		}, nil
 77→	case HookNamePreToolUse:
 78→		return nil, nil
 79→	case HookNamePostToolUse:
 80→		if raw.ToolName != "" {
 81→			a.appendToolCall(raw.ToolName, raw.ToolInput)
 82→		}
 83→		return nil, nil
 84→	case HookNameStop:
 85→		cwd := raw.CWD
 86→		if cwd == "" {
 87→			cwd = protocol.RepoRoot()
 88→		}
 89→		sessionID := a.readCachedSessionID()
 90→		conversationID, _ := a.querySessionID(cwd)
 91→		if sessionID == "" {
 92→			if conversationID != "" {
 93→				sessionID = conversationID
 94→			} else {
 95→				sessionID = fallbackStopSessionID()
 96→			}
 97→		}
 98→		sessionRef := a.captureTranscriptForStop(cwd, sessionID, conversationID)
 99→		a.clearCachedSessionID()
100→		return &protocol.EventJSON{
101→			Type:       3,
102→			SessionID:  sessionID,
103→			SessionRef: sessionRef,
104→			Timestamp:  time.Now().UTC().Format(time.RFC3339),
105→		}, nil
106→	default:
107→		return nil, nil
108→	}
109→}
