521→func tryParseIDETranscript(data []byte) *kiroTranscript {
522→	var ide kiroIDETranscript
523→	if err := json.Unmarshal(data, &ide); err != nil {
524→		return nil
525→	}
526→	if len(ide.History) == 0 || ide.History[0].Message.Role == "" {
527→		return nil
528→	}
529→	return convertIDETranscript(&ide)
530→}
531→
532→func convertIDETranscript(ide *kiroIDETranscript) *kiroTranscript {
533→	transcript := &kiroTranscript{}
534→
535→	var pendingUser *kiroIDEHistoryEntry
536→	for i := range ide.History {
537→		entry := &ide.History[i]
538→		switch entry.Message.Role {
539→		case "user":
540→			if pendingUser != nil {
541→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
542→			}
543→			pendingUser = entry
544→		case "assistant":
545→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
546→			pendingUser = nil
547→		}
548→	}
549→
550→	if pendingUser != nil {
551→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
552→	}
553→
554→	return transcript
555→}
556→
557→func ideEntryToPaired(user, assistant *kiroIDEHistoryEntry) kiroHistoryEntry {
558→	entry := kiroHistoryEntry{}
559→
560→	if user != nil {
561→		prompt := extractIDEText(user.Message.Content, true)
562→		if prompt != "" {
563→			content, err := json.Marshal(kiroPromptContent{
564→				Prompt: struct {
565→					Prompt string `json:"prompt"`
566→				}{Prompt: prompt},
567→			})
568→			if err == nil {
569→				entry.User.Content = content
570→			}
571→		} else {
572→			entry.User.Content = user.Message.Content
573→		}
574→	}
575→
576→	if assistant != nil {
577→		text := extractIDEText(assistant.Message.Content, false)
578→		if text != "" {
579→			content, err := json.Marshal(kiroResponseContent{
580→				Response: kiroResponsePayload{Content: text},
581→			})
582→			if err == nil {
583→				entry.Assistant = content
584→			}
585→		} else {
586→			entry.Assistant = assistant.Message.Content
587→		}
588→	}
589→
590→	return entry
591→}
592→
593→// extractIDEText extracts text from a json.RawMessage that may be either a
594→// plain string or an array of content blocks. When blocksFirst is true, it
595→// tries to parse as blocks before falling back to a plain string (user
596→// messages); otherwise it tries plain string first (assistant messages).
597→func extractIDEText(content json.RawMessage, blocksFirst bool) string {
598→	if len(content) == 0 {
599→		return ""
600→	}
601→
602→	tryBlocks := func() string {
603→		var blocks []kiroIDEContentBlock
604→		if err := json.Unmarshal(content, &blocks); err == nil && len(blocks) > 0 {
605→			for _, block := range blocks {
606→				if block.Type == "text" && block.Text != "" {
607→					return block.Text
608→				}
609→			}
610→		}
611→		return ""
612→	}
613→
614→	tryString := func() string {
615→		var text string
616→		if err := json.Unmarshal(content, &text); err == nil {
617→			return text
618→		}
619→		return ""
620→	}
621→
622→	if blocksFirst {
623→		if s := tryBlocks(); s != "" {
624→			return s
625→		}
626→		return tryString()
627→	}
628→	if s := tryString(); s != "" {
629→		return s
630→	}
631→	return tryBlocks()
632→}
633→
634→func extractUserPrompt(content json.RawMessage) string {
635→	if len(content) == 0 {
636→		return ""
637→	}
638→
639→	var promptContent kiroPromptContent
640→	if err := json.Unmarshal(content, &promptContent); err == nil && promptContent.Prompt.Prompt != "" {
641→		return promptContent.Prompt.Prompt
642→	}
643→	return ""
644→}
