646→func extractModifiedFilesFromHistory(entries []kiroHistoryEntry) []string {
647→	seen := make(map[string]bool)
648→	var files []string
649→
650→	for i := range entries {
651→		for _, path := range extractFilesFromAssistant(entries[i].Assistant) {
652→			if path == "" || seen[path] {
653→				continue
654→			}
655→			seen[path] = true
656→			files = append(files, path)
657→		}
658→	}
659→
660→	return files
661→}
662→
663→func extractFilesFromAssistant(raw json.RawMessage) []string {
664→	if len(raw) == 0 {
665→		return nil
666→	}
667→
668→	var toolUseContent kiroToolUseContent
669→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
670→		return nil
671→	}
672→
673→	var paths []string
674→	for _, call := range toolUseContent.ToolUse.ToolUses {
675→		if !isFileModificationTool(call.Name) {
676→			continue
677→		}
678→		if path := extractFilePath(call.Args); path != "" {
679→			paths = append(paths, path)
680→		}
681→	}
682→	return paths
683→}
684→
685→func isFileModificationTool(name string) bool {
686→	_, ok := kiroFileModificationTools[name]
687→	return ok
688→}
689→
690→func extractFilePath(args json.RawMessage) string {
691→	if len(args) == 0 {
692→		return ""
693→	}
694→
695→	var fields map[string]json.RawMessage
696→	if err := json.Unmarshal(args, &fields); err != nil {
697→		return ""
698→	}
699→
700→	for _, key := range []string{"path", "file_path", "filename", "file"} {
701→		raw, ok := fields[key]
702→		if !ok {
703→			continue
704→		}
705→		var path string
706→		if err := json.Unmarshal(raw, &path); err == nil && path != "" {
707→			return path
708→		}
709→	}
710→	return ""
711→}
712→
713→func extractLastAssistantResponse(entries []kiroHistoryEntry) string {
714→	for i := len(entries) - 1; i >= 0; i-- {
715→		if len(entries[i].Assistant) == 0 {
716→			continue
717→		}
718→
719→		var responseContent kiroResponseContent
720→		if err := json.Unmarshal(entries[i].Assistant, &responseContent); err == nil && responseContent.Response.Content != "" {
721→			return responseContent.Response.Content
722→		}
723→	}
724→	return ""
725→}
726→
727→// --- Execution log enrichment ---
728→
729→// extractIDESessionID parses the sessionId from an IDE session JSON file.
730→func extractIDESessionID(data []byte) string {
731→	var meta kiroIDESessionMeta
732→	if err := json.Unmarshal(data, &meta); err != nil {
733→		return ""
734→	}
735→	return meta.SessionID
736→}
737→
738→// extractIDEExecutionIDs parses executionId values from assistant entries
739→// in an IDE session JSON file.
740→func extractIDEExecutionIDs(data []byte) []string {
741→	var meta kiroIDESessionMeta
742→	if err := json.Unmarshal(data, &meta); err != nil {
743→		return nil
744→	}
745→	var ids []string
746→	for _, entry := range meta.History {
747→		if entry.ExecutionID != "" {
748→			ids = append(ids, entry.ExecutionID)
749→		}
750→	}
751→	return ids
752→}
753→
754→// findExecutionLogsForSession scans Kiro IDE workspace directories to find
755→// execution log files matching the given chat session ID. Returns a map of
756→// executionId → *kiroExecutionLog.
757→func findExecutionLogsForSession(chatSessionID string) (map[string]*kiroExecutionLog, error) {
758→	baseDir, err := kiroExtensionStorageDir()
759→	if err != nil {
760→		return nil, err
761→	}
762→
763→	entries, err := os.ReadDir(baseDir)
764→	if err != nil {
765→		return nil, err
766→	}
767→
768→	for _, entry := range entries {
769→		if !entry.IsDir() || len(entry.Name()) != 32 {
770→			continue
771→		}
772→		logsDir := filepath.Join(baseDir, entry.Name(), execLogsSubdir)
773→		if _, err := os.Stat(logsDir); err != nil {
774→			continue
775→		}
776→		logs := scanExecutionLogsDir(logsDir, chatSessionID)
777→		if len(logs) > 0 {
778→			return logs, nil
779→		}
780→	}
781→
782→	return map[string]*kiroExecutionLog{}, nil
783→}
784→
785→// scanExecutionLogsDir reads all execution log files in a directory and returns
786→// those matching the given chat session ID.
787→func scanExecutionLogsDir(dir string, chatSessionID string) map[string]*kiroExecutionLog {
788→	files, err := os.ReadDir(dir)
789→	if err != nil {
790→		return nil
791→	}
792→
793→	// Two-pass approach: first identify matching files using a lightweight
794→	// struct (avoids deserializing the large Actions array), then fully
795→	// parse only the matches.
796→	var matchingPaths []string
797→	for _, f := range files {
798→		if f.IsDir() {
799→			continue
800→		}
801→		path := filepath.Join(dir, f.Name())
802→		data, err := os.ReadFile(path)
803→		if err != nil {
804→			continue
805→		}
806→		var header struct {
807→			ChatSessionID string `json:"chatSessionId"`
808→		}
809→		if json.Unmarshal(data, &header) == nil && header.ChatSessionID == chatSessionID {
810→			matchingPaths = append(matchingPaths, path)
811→		}
812→	}
813→
814→	if len(matchingPaths) == 0 {
815→		return nil
816→	}
817→
818→	result := make(map[string]*kiroExecutionLog, len(matchingPaths))
819→	for _, path := range matchingPaths {
820→		data, err := os.ReadFile(path)
821→		if err != nil {
822→			continue
823→		}
824→		var log kiroExecutionLog
825→		if err := json.Unmarshal(data, &log); err != nil {
826→			continue
827→		}
828→		result[log.ExecutionID] = &log
829→	}
830→	return result
831→}
832→
833→// convertExecutionActionsToHistoryEntries converts Kiro IDE execution log
834→// actions into CLI transcript history entries. Tool-modifying actions (create,
835→// edit) become ToolUse entries; say actions become Response entries.
836→func convertExecutionActionsToHistoryEntries(actions []kiroExecutionAction) []kiroHistoryEntry {
837→	var toolCalls []kiroToolCall
838→	var entries []kiroHistoryEntry
839→
840→	for _, action := range actions {
841→		if toolName, ok := execActionToToolName[action.ActionType]; ok {
842→			filePath := extractFilePath(action.Input)
843→			if filePath != "" {
844→				args, _ := json.Marshal(map[string]string{"path": filePath})
845→				toolCalls = append(toolCalls, kiroToolCall{
846→					Name: toolName,
847→					Args: args,
848→				})
849→			}
850→		}
851→		if action.ActionType == "say" {
852→			var out struct {
853→				Message string `json:"message"`
854→			}
855→			if err := json.Unmarshal(action.Output, &out); err == nil && out.Message != "" {
856→				// Flush any pending tool calls first
857→				if len(toolCalls) > 0 {
858→					toolUseJSON, _ := json.Marshal(kiroToolUseContent{
859→						ToolUse: kiroToolUsePayload{ToolUses: toolCalls},
860→					})
861→					entries = append(entries, kiroHistoryEntry{Assistant: toolUseJSON})
862→					toolCalls = nil
863→				}
864→				responseJSON, _ := json.Marshal(kiroResponseContent{
865→					Response: kiroResponsePayload{Content: out.Message},
866→				})
867→				entries = append(entries, kiroHistoryEntry{Assistant: responseJSON})
868→			}
869→		}
870→	}
871→
872→	// Flush remaining tool calls without a trailing say
873→	if len(toolCalls) > 0 {
874→		toolUseJSON, _ := json.Marshal(kiroToolUseContent{
875→			ToolUse: kiroToolUsePayload{ToolUses: toolCalls},
876→		})
877→		entries = append(entries, kiroHistoryEntry{Assistant: toolUseJSON})
878→	}
879→
880→	return entries
881→}
882→
883→// enrichIDETranscriptWithExecutionLogs converts an IDE transcript to CLI
884→// format and replaces "On it." assistant entries with actual data from
885→// execution logs. Returns the re-serialized CLI-format JSON, or nil if
886→// conversion fails.
887→func enrichIDETranscriptWithExecutionLogs(ideData []byte, execLogs map[string]*kiroExecutionLog) []byte {
888→	var meta kiroIDESessionMeta
889→	if err := json.Unmarshal(ideData, &meta); err != nil {
890→		return nil
891→	}
892→	if len(meta.History) == 0 {
893→		return nil
894→	}
895→
896→	// Convert to CLI format, enriching assistant entries from execution logs.
897→	// kiroIDEHistoryMeta contains both the Message (for pairing) and the
898→	// ExecutionID (for matching against execution logs).
899→	transcript := &kiroTranscript{}
900→	var pendingUser *kiroIDEHistoryEntry
901→	for i := range meta.History {
902→		// Adapt meta entry to IDE entry (they share the same Message field)
903→		ideEntry := &kiroIDEHistoryEntry{Message: meta.History[i].Message}
904→		switch ideEntry.Message.Role {
905→		case "user":
906→			if pendingUser != nil {
907→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
908→			}
909→			pendingUser = ideEntry
910→		case "assistant":
911→			if execID := meta.History[i].ExecutionID; execID != "" {
912→				if execLog, ok := execLogs[execID]; ok {
913→					userEntry := ideEntryToPaired(pendingUser, nil)
914→					assistantEntries := convertExecutionActionsToHistoryEntries(execLog.Actions)
915→					if len(assistantEntries) > 0 {
916→						userEntry.Assistant = assistantEntries[0].Assistant
917→						transcript.History = append(transcript.History, userEntry)
918→						for _, extra := range assistantEntries[1:] {
919→							transcript.History = append(transcript.History, extra)
920→						}
921→						pendingUser = nil
922→						continue
923→					}
924→				}
925→			}
926→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, ideEntry))
927→			pendingUser = nil
928→		}
929→	}
930→	if pendingUser != nil {
931→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
932→	}
933→
934→	result, err := json.Marshal(transcript)
935→	if err != nil {
936→		return nil
937→	}
938→	return result
939→}
