func TestChunkTranscriptRoundTrip(t *testing.T) {
	original := []byte("REDACTED")

	chunks, err := New().ChunkTranscript(original, 8)
	if err != nil {
		t.Fatalf("ChunkTranscript() error = %v", err)
	}
	if len(chunks) < 2 {
		t.Fatalf("expected multiple chunks, got %d", len(chunks))
	}
