			}
			return buildTranscript("cli-session", 1), nil
		default:
			t.Fatalf("unexpected sqlite args count: %d", len(args))
			return nil, nil
		}
	})
	defer restore()

	seedSessionIDCache(t, repoRoot, "stable-session")

