		t.Fatalf("write IDE transcript: %v", err)
	}

	// Offset already at position 1 — no new entries since last checkpoint.
	// The IDE transcript has 1 pair, and offset says we already captured 1.
	// trimTranscriptHistory returns (nil, false) when trimFrom==0 || trimFrom>=totalLen,
	// so the full transcript is kept. But the empty-history guard won't trigger
	// because there IS content. The function should still succeed with the full
	// transcript (same behavior as ensureCachedTranscript's no-new-entries case).
	seedTranscriptOffset(t, repoRoot, "", 1)

